    \node at ({3*sqrt(3)/4},-0.25) {$\gamma_c$};
    \node at ({3*sqrt(3)/2+0.25}, 0.75) {$\gamma_v$};
    \node at (42:1.5) {$\delta_x\alpha_x$};
